// 1. Dereference raw pointers
fn raw_pointer_example() {
    let x = 42;
    let ptr: *const i32 = &x;
    unsafe {
        println!("Value: {}", *ptr);
    }
}

// 2. Call unsafe functions
unsafe fn dangerous() -> i32 {
    // This function's contract must be upheld by callers
    42
}

fn call_unsafe() {
    let value = unsafe { dangerous() };
    println!("{}", value);
}

// 3. Access mutable statics
static mut COUNTER: u64 = 0;

fn increment() {
    unsafe {
        COUNTER += 1;
    }
}

// 4. Implement unsafe traits
// (Send and Sync are the most common unsafe traits)

// 5. Access union fields
union IntOrFloat {
    i: i32,
    f: f32,
}

fn union_example() {
    let u = IntOrFloat { i: 42 };
    unsafe {
        println!("As int: {}", u.i);
    }
}

fn still_checked() {
    let mut x = 5;
    let r1 = &x;
    // let r2 = &mut x;  // Still a compile error, even in unsafe!
    println!("{}", r1);

    unsafe {
        // Ownership and borrowing rules still apply.
        // Unsafe only adds the five superpowers listed above.
        let ptr: *const i32 = &x;
        println!("{}", *ptr);
    }
}
